definition.script:
import groovy.json.JsonSlurper;

def infrastructure_git_hash

pipeline {
  agent any

  options {
    skipDefaultCheckout(true)
  }

  stages {
    stage('Resolve Infrastructure Git Hash') {
      steps {
        script {
          if (params.INFRASTRUCTURE_GIT_HASH?.trim()) {
            infrastructure_git_hash = params.INFRASTRUCTURE_GIT_HASH.trim()
            echo "Using provided INFRASTRUCTURE_GIT_HASH: ${infrastructure_git_hash}"
          } else {
            def result = build job: 'Retrieve Build Spec'
            copyArtifacts filter: 'build-spec.json', projectName: 'Retrieve Build Spec', selector: specific("" + result.number)
            def buildSpec = new JsonSlurper().parse(new File("${env.WORKSPACE}/build-spec.json"))
            infrastructure_git_hash = buildSpec.infrastructure_git_hash
            echo "Resolved INFRASTRUCTURE_GIT_HASH from release control: ${infrastructure_git_hash}"
          }
        }
      }
    }

    stage('Checkout Infrastructure Repo') {
      steps {
        checkout([
          $class: 'GitSCM',
          userRemoteConfigs: [[
            url: "${infrastructure_git_repo}",
            credentialsId: "${git_credentials_id}"
          ]],
          branches: [[name: infrastructure_git_hash]]
        ])
      }
    }

    stage('Download Templates') {
      steps {
        script {
          def repoTemplateDir = 'app-infrastructure/template-renderer/templates'
          def targetStack = params.TARGET_STACK?.trim() ?: ''

          // Source bash functions
          sh '''#!/bin/bash
            source_scripts_folder="${JENKINS_HOME}/workspace/Bash_Functions/"
            for script_file in "$source_scripts_folder"*.sh; do
                chmod +x "$script_file"
                if [ -f "$script_file" ] && [ -x "$script_file" ]; then
                    source "$script_file"
                fi
            done
          '''

          // Download hpds-auth.env.tftpl
          def authFound = false
          if (targetStack) {
            authFound = sh(script: "aws s3 cp s3://\${stack_s3_bucket}/configs/hpds/templates/${targetStack}/hpds-auth.env.tftpl hpds-auth.env.tftpl", returnStatus: true) == 0
            if (authFound) echo "Using stack-specific S3 template for hpds-auth.env.tftpl"
          }
          if (!authFound) {
            authFound = sh(script: "aws s3 cp s3://\${stack_s3_bucket}/configs/hpds/templates/hpds-auth.env.tftpl hpds-auth.env.tftpl", returnStatus: true) == 0
            if (authFound) echo "Using shared S3 template for hpds-auth.env.tftpl"
          }
          if (!authFound) {
            echo "No S3 template found, using repo version of hpds-auth.env.tftpl"
            sh "cp ${repoTemplateDir}/hpds-auth.env.tftpl hpds-auth.env.tftpl"
          }

          // Download hpds-open.env.tftpl
          def openFound = false
          if (targetStack) {
            openFound = sh(script: "aws s3 cp s3://\${stack_s3_bucket}/configs/hpds/templates/${targetStack}/hpds-open.env.tftpl hpds-open.env.tftpl", returnStatus: true) == 0
            if (openFound) echo "Using stack-specific S3 template for hpds-open.env.tftpl"
          }
          if (!openFound) {
            openFound = sh(script: "aws s3 cp s3://\${stack_s3_bucket}/configs/hpds/templates/hpds-open.env.tftpl hpds-open.env.tftpl", returnStatus: true) == 0
            if (openFound) echo "Using shared S3 template for hpds-open.env.tftpl"
          }
          if (!openFound) {
            echo "No S3 template found, using repo version of hpds-open.env.tftpl"
            sh "cp ${repoTemplateDir}/hpds-open.env.tftpl hpds-open.env.tftpl"
          }
        }
      }
    }
  }

  post {
    success {
      archiveArtifacts artifacts: 'hpds-auth.env.tftpl,hpds-open.env.tftpl', allowEmptyArchive: true
    }
  }
}
